fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut count = 0;

    for i in 0..n {
        for j in i + 1..n {
            let a = nums[i];
            let b = nums[j];
            let min_abs = std::cmp::min(a.abs(), b.abs());
            let max_abs = std::cmp::max(a.abs(), b.abs());

            let diff = (a - b).abs();
            let sum = (a + b).abs();

            let min_val = std::cmp::min(diff, sum);
            let max_val = std::cmp::max(diff, sum);

            if min_val <= min_abs && max_val >= max_abs {
                count += 1;
            }
        }
    }

    count
}
